1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("QUOTE - base prices (first insurance, year 0, no other modifiers)", () => {
6	    // Base premium * 1.10 (first insurance) + 5 (fee), rounded up
7	    it("quotes an empty item list at just the processing fee — 5 G", () => {
8	      expect(quote({ yearsWithMHPCO: 0 }, [])).toBe(5);
9	    });
10	    it.todo("quotes a plain sword at 115 G (100 * 1.10 + 5)");
11	    it.todo("quotes a plain amulet at 71 G (60 * 1.10 + 5)");
12	    it.todo("quotes a plain staff at 93 G (80 * 1.10 + 5)");
13	    it.todo("quotes a plain potion at 49 G (40 * 1.10 + 5)");
14	    it.todo("quotes a single rune at 33 G (25 * 1.10 = 27.5 → 28 + 5)");
15	    it.todo("quotes a single moonstone at 33 G (25 * 1.10 = 27.5 → 28 + 5)");
16	  });
17	
18	  describe("QUOTE - component bundle special pricing", () => {
19	    it.todo("quotes 3 alike runes at the bundle price 71 G (60 * 1.10 + 5), not 3 * 33");
20	    it.todo("quotes 3 alike moonstones at the bundle price 71 G (60 * 1.10 + 5)");
21	  });
22	
23	  describe("QUOTE - risk surcharges (single sword, first insurance, year 0)", () => {
24	    it.todo("adds 50% surcharge for a cursed sword — 170 G (100 * 1.5 * 1.10 + 5)");
25	    it.todo("adds 30% surcharge for a highly enchanted sword (enchantment 5) — 148 G (100 * 1.3 * 1.10 + 5)");
26	    it.todo("does not add the enchantment surcharge for enchantment 4 — 115 G");
27	    it.todo("stacks both surcharges for a cursed highly enchanted sword — 220 G (100 * 1.5 * 1.3 * 1.10 = 214.5 → 215 + 5)");
28	  });
29	
30	  describe("QUOTE - customer discounts", () => {
31	    it.todo("applies 20% loyalty discount for a customer with 2 years — 93 G (100 * 0.8 * 1.10 + 5)");
32	    it.todo("does not apply loyalty discount for a customer with 1 year — 115 G");
33	    it.todo("applies 20% loyalty discount for a customer with 5 years — 93 G");
34	  });
35	
36	  describe("QUOTE - contract sequence discounts", () => {
37	    it.todo("applies 10% first-insurance surcharge on the first quote — sword at 115 G");
38	    it.todo("applies 15% discount on the second quote in a scenario — sword at 90 G (100 * 0.85 + 5)");
39	    it.todo("applies 15% discount on the third quote in a scenario — sword at 90 G");
40	  });
41	
42	  describe("QUOTE - rounding in MHPCO's favor", () => {
43	    it.todo("rounds fractional premiums up to whole G (rune 27.5 → 28, then + 5 = 33 G)");
44	  });
45	
46	  describe("QUOTE - multiple items in one quote", () => {
47	    it.todo("sums premiums across mixed items with a single processing fee — sword + amulet at 181 G (110 + 66 + 5)");
48	  });
49	
50	  describe("CLAIM - reimbursement rules", () => {
51	    it.todo("pays 0 for damage to an item that is neither high-enchantment nor dragon material");
52	    it.todo("pays 50% of damage minus 100 G deductible for an item with enchantment 8 — damage 400 → payout 100 G");
53	    it.todo("does not apply 50% rule for enchantment 7 — payout 0");
54	    it.todo("pays full damage minus 100 G deductible for a dragon-material item — damage 500 → payout 400 G");
55	    it.todo("applies a single 100 G deductible per damage event, not per damaged item");
56	    it.todo("sums reimbursements across multiple damaged items in one incident before subtracting the deductible");
57	    it.todo("never returns a negative payout (small damage below the deductible yields 0)");
58	  });
59	
60	  describe("CLAIM - references the correct policy", () => {
61	    it.todo("uses the items from the policy identified by the zero-based policy index when matching itemType");
62	  });
63	});
